var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건배애애애!","JPN":"乾杯～！","ENG":"CHEEEERS!","TWN":"乾杯～～！！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"캬아, 오늘따라 맥주 맛 한 번 끝내 주네!","JPN":"くう、今日のビールは格別にうまいな！","ENG":"Oh, man! Victory beer tastes so good!","TWN":"哈～！今天的啤酒特別好喝呢！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"너무 과음하지 마요, 라이카. 괜히 만취해서 사고치지 말고.","JPN":"飲みすぎないでよ、ライカ。酔っぱらって問題なんか起こさないように。","ENG":"Don't drink too much, Laika. Or you'll get drunk and cause trouble again.","TWN":"萊卡，你不要喝太多，到時候喝醉又闖禍。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"걱정도 팔자다. 이런 날 안 마시면 언제 마셔?","JPN":"心配性だな。こんな日に飲まずにいつ飲めってんだよ？","ENG":"What are you, my mom? When else will I drink if not today?","TWN":"哎唷，你不要囉嗦啦，此時不喝待何時？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시원시원해서 좋구만. 마음에 들었어!","JPN":"スカッとしてていいねぇ。気に入った！","ENG":"You speak my language. I like your style!","TWN":"爽快！我喜歡！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"스태프 아가씨도 한 잔 받게! 오늘의 주인공이잖아!","JPN":"スタッフのお嬢ちゃんも一杯やんな！　今日の主人公だろ！","ENG":"Staff girl, I'll pour you a glass! You're the MVP today!","TWN":"駕駛員也喝一杯吧！你是今天的大功臣欸！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아하하…. 아니에요. 다 햄스워스 씨 덕분이죠.","JPN":"あはは……とんでもない。ヘムズワースさんのおかげですよ。","ENG":"Ah hah hah... You're too kind. It was all thanks to you, Mr. Helmsworth.","TWN":"哈哈…沒有啦，都是托你的福。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"보아하니 보통 실력이 아니던데, 채굴 작전에는 관심 없나?","JPN":"見たところかなりの実力だったが、採掘作戦には興味ないか？","ENG":"You got some skills, though. Ever thought about working in the mines?","TWN":"你的能力很好呢，對採礦作戰有興趣嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"괜찮다면 내가 좋은 팀으로 소개시켜 주지.","JPN":"よかったら、ワシがいいチームを紹介してやろう。","ENG":"If you're up for it, I can introduce you to a fantastic team I know.","TWN":"要我替你介紹幾個不錯的隊嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저, 말씀은 감사하지만 저는…….","JPN":"あの、お言葉はありがたいのですが、私は……","ENG":"Uh... Thank you, but I'm...","TWN":"謝謝你的好意，但我……"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어이, 할배. 지금 우리 스태프한테 무슨 수작을 부리는 거야?","JPN":"おい、ジジイ。うちのスタッフを何口説いてんだよ？","ENG":"Hey, gramps. You trying to take away our staff?","TWN":"喂，這位阿公！你想對我們的駕駛員做什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스키너를 데려가면 가만 안 놔둘 줄 알아요.","JPN":"スキナーを連れ出したら許しませんよ。","ENG":"I'll be your worst nightmare if you take Skinner away from us.","TWN":"你要是敢帶走史金納，我可不會放過你。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희들…….","JPN":"みんな……","ENG":"Gals...","TWN":"你們……"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이거 보기보다 팀원끼리 우정이 꽤 끈끈한데?","JPN":"こりゃあ、意外とチームメンバー同士で仲がいいんだな。","ENG":"Whoa, aren't you like the three musketeers!","TWN":"沒想到你們的友情這麼堅定？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"좋아. 그럼 이 아가씨가 자리를 비운 동안 자네들 함선을 무상으로 수리해 주지.","JPN":"よし。それじゃあ、こっちのお嬢ちゃんがいない間はワシが艦船をタダで修理するというのはどうだ。","ENG":"All right. Then while she's away, I'll repair your ship free of charge.","TWN":"好吧！那她不在的這段時間，我就免費替你們修理艦船吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};